      if (prefix) return size === "sm" ? "pr-2" : size === "lg" ? "pr-3" : "pr-3";
      if (suffix) return size === "sm" ? "pl-2" : size === "lg" ? "pl-3" : "pl-3";
      return size === "sm" ? "px-3" : size === "lg" ? "px-4" : "px-3.5";
